import type { FilterSignalData } from 'signals/filters';
import { price } from 'utils/format';
import { localize } from 'i18n/localize';

const {
	offerList,
	offerList: { emptyState: emptyState },
} = localize();

export function formatTitle(filters: FilterSignalData) {
	const { price: priceFilter, category: categoryFilter } = filters;
	const categoryName = categoryFilter?.id && categoryFilter?.name;
	const formattedCategory = categoryName ? ` ${emptyState.inCategory} ${categoryName}` : '';
	const formattedPrice =
		priceFilter.type === 'zdarma'
			? ` ${emptyState.betweenPrice} ${emptyState.free}`
			: priceFilter.to || priceFilter.from
				? ` ${emptyState.betweenPrice} ${priceFilter.from ? `${emptyState.from} ${price(priceFilter.from)}` : ''}${priceFilter.from && priceFilter.to ? ' ' : ''}${priceFilter.to ? `${emptyState.to} ${price(priceFilter.to)}` : ''}`
				: '';
	return `${offerList.emptyStateTitleOffers}${formattedCategory}${formattedPrice}`;
}
