import { Signal } from '@preact/signals';
import { offers as offersSignal } from 'signals/offers';
import { OfferCardList, SEARCH_GRID_SIZING } from 'components/offer/list/OfferList';
import { SignalsProvider } from 'context/SignalsContext';
import { formatTitle } from 'utils/formatEmptyState';
import { OFFERS_PER_PAGE } from 'utils/constants';
import { isQueryOffersLoading, isQueryOffersAppend } from 'signals/queryOffers';
import { searchPageAdInserter } from 'components/offer/list/adInserters/searchPageAdInserter';
import type { GetMixedOffersSearchResponse } from 'service/offer/resource';
import { filters } from 'signals/filters';

type Props = {
	offers: GetMixedOffersSearchResponse;
};

export function SearchPageList({ offers }: Props) {
	return (
		<SignalsProvider
			value={{
				offers: new Signal({
					response: offersSignal.value ?? offers,
					isLoading: isQueryOffersLoading.value,
					isAppend: isQueryOffersAppend.value,
				}),
			}}
		>
			<OfferCardList
				adInserter={searchPageAdInserter}
				emptyStateTitle={formatTitle(filters.peek())}
				gridSizing={SEARCH_GRID_SIZING}
				eagerFirstImage={true}
				positionOffset={((filters.peek().page.value ?? 1) - 1) * OFFERS_PER_PAGE}
			/>
		</SignalsProvider>
	);
}
